FUNCTION PowerCHT(A, k)
 n ← SIZE(A)
 I ← IDENTITY_MATRIX(n)

 // Compute characteristic polynomial coefficients
 coeffs[] ← CHARACTERISTIC_COEFFICIENTS(A)
 // coeffs[i] = c_i for λ^i term

 // Use binary exponentiation with reduction
 // Precompute powers: I, A, A², ..., A^(n-1)
 base_powers[0] ← I
 base_powers[1] ← A
 FOR i FROM 2 TO n-1 DO
 base_powers[i] ← base_powers[i-1] * A
 END FOR

 // Reduce k to linear combination of 0 to n-1 powers
 // Using recurrence: A^n = -c_{n-1}A^{n-1} - ... - c_1A - c_0I
 // This gives us linear recurrence for powers
 result ← I
 temp ← I
 power ← k

 WHILE power > 0 DO
 IF power MOD 2 == 1 THEN
 result ← result * temp
 END IF
 temp ← temp * temp
 // Reduce temp using characteristic polynomial
 temp ← REDUCE_USING_CHT(temp, coeffs)
 power ← power DIV 2
 END WHILE

 RETURN result
END FUNCTION

