FUNCTION FaddeevLeVerrier(A)
 n ← SIZE(A)
 I ← IDENTITY_MATRIX(n)
 coeffs[] ← ARRAY of size n
 B[0] ← I

 // c_0 = (-1)^n * det(A) = -tr(A) for n=1
 // General recurrence: c_k = -(1/k) * tr(A * B_{k-1} + c_{k-1}I)

 FOR k FROM 1 TO n DO
 IF k == 1 THEN
 coeffs[0] ← -TRACE(A)
 B[1] ← A * B[0] + coeffs[0] * I
 ELSE
 temp ← A * B[k-1]
 coeffs[k-1] ← -(1/k) * TRACE(temp)
 B[k] ← temp + coeffs[k-1] * I
 END IF
 END FOR

 // Characteristic polynomial: λ^n + c_{n-1}λ^{n-1} + ... + c_1λ + c_0
 RETURN coeffs
END FUNCTION

